/**
 * Shared parsing + validation for the task-list query params.
 *
 * Used by both task-list routes so the Bearer/CLI sibling
 * (GET /api/teams/[teamId]/tasks) and the explorer session route
 * (GET /api/explorer/tasks) harden identically:
 *
 *   FIX #1 — limit: NaN / <1 / negative fall back to 50; clamp to 500.
 *            parseInt("abc") → NaN; parseInt("0") → 0; either would
 *            otherwise produce LIMIT NULL / LIMIT 0; limit=-1 returned ALL rows.
 *   FIX #2 — cursor: unparseable timestamps are rejected before hitting SQL.
 *            new Date("garbage").getTime() === NaN → would render
 *            `LIMIT <Invalid Date>` and 500. Caller returns 400 'Invalid cursor'.
 *
 * Pure function — no I/O, no NextResponse — so it stays trivially testable and
 * both routes share one source of truth. The route owns the HTTP response:
 * when `error` is set, respond 400 with that message.
 */

export interface TaskListParams {
  projectId: string | null;
  status: string | null;
  q: string | null;
  /** Always a finite integer in [1, 500]. */
  limit: number;
  /** Parsed cursor bound, or null when no cursor was supplied. */
  cursorDate: Date | null;
  /** Set when a param failed validation (e.g. unparseable cursor). */
  error: string | null;
}

export function parseTaskListParams(
  searchParams: URLSearchParams
): TaskListParams {
  const projectId = searchParams.get("project_id");
  const status = searchParams.get("status");
  const q = searchParams.get("q");

  // FIX #1 — limit hardening.
  const rawLimit = parseInt(searchParams.get("limit") ?? "50", 10);
  const limit =
    isNaN(rawLimit) || rawLimit < 1 ? 50 : Math.min(rawLimit, 500);

  // FIX #2 — cursor hardening.
  const cursorStr = searchParams.get("cursor");
  let cursorDate: Date | null = null;
  if (cursorStr != null) {
    cursorDate = new Date(cursorStr);
    if (isNaN(cursorDate.getTime())) {
      return {
        projectId,
        status,
        q,
        limit,
        cursorDate: null,
        error: "Invalid cursor",
      };
    }
  }

  return { projectId, status, q, limit, cursorDate, error: null };
}

/**
 * Shared task-close (soft-signal tombstone) helper.
 *
 * Both close routes (Bearer/CLI team route and session-gated explorer route)
 * perform identical writes after their own auth: they merge a soft-signal
 * tombstone into sync_entities.data so the local CLI can reconcile on the next
 * `cas cloud sync`. The only differences were the auth layer in front of them.
 *
 * The server has NO lease/worktree awareness — it records intent only:
 *   data.status       = 'closed'
 *   data.close_reason = reason (empty string if omitted)
 *   data.closed_at    = now (ISO-8601)
 *   data.closed_via   = 'web'
 *   updated_at        = now  ← bumped so CLI pull picks it up
 *
 * Idempotency: a second close on an already-closed task does NOT re-write the
 * tombstone or re-bump updated_at. The original close_reason / closed_at /
 * updated_at are preserved (the audit trail stays intact, and the CLI does not
 * needlessly re-reconcile).
 */

import { sql } from "drizzle-orm";
import { db } from "@/lib/db";

export const MAX_CLOSE_REASON_CHARS = 2000;

/** A close-signal row as returned to API clients. */
export type CloseSignal = {
  id: unknown;
  status: unknown;
  close_reason: unknown;
  closed_at: unknown;
  closed_via: unknown;
  updated_at: string | unknown;
};

export type ReasonResult = { reason: string } | { error: string };

/**
 * Validates the optional `reason` field from a close POST body.
 *
 * Returns `{ reason }` (empty string when omitted/null) on success, or
 * `{ error }` with a message the caller should return as a 400.
 */
export function validateCloseReason(payload: unknown): ReasonResult {
  const p =
    typeof payload === "object" && payload !== null
      ? (payload as Record<string, unknown>)
      : {};

  if (
    "reason" in p &&
    p.reason !== undefined &&
    p.reason !== null &&
    typeof p.reason !== "string"
  ) {
    return { error: "reason must be a string" };
  }

  const reason = typeof p.reason === "string" ? p.reason : "";

  if (reason.length > MAX_CLOSE_REASON_CHARS) {
    return { error: "reason exceeds maximum length" };
  }

  return { reason };
}

/** Normalize an updated_at value to an ISO string for the response. */
function isoUpdatedAt(value: unknown): unknown {
  return value instanceof Date ? value.toISOString() : value;
}

/**
 * Writes the soft-signal close tombstone for a task, idempotently.
 *
 * - If the task exists and is not yet closed → writes the tombstone, bumps
 *   updated_at, and returns the new signal fields.
 * - If the task exists and is already closed → returns the EXISTING signal
 *   fields without re-writing (updated_at is NOT re-bumped).
 * - If the task does not exist in this team → returns null (caller → 404).
 *
 * @param teamId  the task's team (already authorized by the caller)
 * @param taskId  the task id
 * @param reason  validated close reason (use validateCloseReason first)
 */
export async function writeCloseSignal(
  teamId: string,
  taskId: string,
  reason: string
): Promise<CloseSignal | null> {
  const now = new Date();
  const closedAt = now.toISOString();

  // Only write the tombstone if the task is not already closed.
  // IS DISTINCT FROM treats a missing 'status' (NULL) as != 'closed'.
  const updateResult = await db.execute(sql`
    UPDATE sync_entities
    SET
      data       = data || jsonb_build_object(
                     'status',       'closed',
                     'close_reason', ${reason},
                     'closed_at',    ${closedAt},
                     'closed_via',   'web'
                   ),
      updated_at = ${now}
    WHERE id          = ${taskId}
      AND entity_type = 'task'
      AND team_id     = ${teamId}
      AND data->>'status' IS DISTINCT FROM 'closed'
    RETURNING
      id,
      data->>'status'       AS status,
      data->>'close_reason' AS close_reason,
      data->>'closed_at'    AS closed_at,
      data->>'closed_via'   AS closed_via,
      updated_at
  `);

  if (updateResult.rows.length > 0) {
    const row = (updateResult.rows as Array<Record<string, unknown>>)[0];
    return {
      id: row.id,
      status: row.status,
      close_reason: row.close_reason,
      closed_at: row.closed_at,
      closed_via: row.closed_via,
      updated_at: isoUpdatedAt(row.updated_at),
    };
  }

  // 0 rows updated: either the task is already closed, or it doesn't exist.
  // Re-SELECT to distinguish and, if already closed, return its existing fields
  // WITHOUT re-bumping updated_at.
  const selectResult = await db.execute(sql`
    SELECT
      id,
      data->>'status'       AS status,
      data->>'close_reason' AS close_reason,
      data->>'closed_at'    AS closed_at,
      data->>'closed_via'   AS closed_via,
      updated_at
    FROM sync_entities
    WHERE id          = ${taskId}
      AND entity_type = 'task'
      AND team_id     = ${teamId}
    LIMIT 1
  `);

  if (selectResult.rows.length === 0) {
    return null;
  }

  const row = (selectResult.rows as Array<Record<string, unknown>>)[0];
  return {
    id: row.id,
    status: row.status,
    close_reason: row.close_reason,
    closed_at: row.closed_at,
    closed_via: row.closed_via,
    updated_at: isoUpdatedAt(row.updated_at),
  };
}

